import{_ as o,o as e,c as r,a3 as a}from"./chunks/framework.DACwFHq9.js";const b=JSON.parse('{"title":"VCP 连接器","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/vcp-connector.md","filePath":"user-guide/tools/vcp-connector.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/vcp-connector.md"};function d(i,t,n,s,h,u){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="vcp-连接器" tabindex="-1">VCP 连接器 <a class="header-anchor" href="#vcp-连接器" aria-label="Permalink to &quot;VCP 连接器&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>VCP 连接器是 AIO Hub 与 <a href="https://github.com/lioensky/VCPToolBox" target="_blank" rel="noreferrer">VCP (Variable &amp; Command Protocol)</a> 生态系统之间的桥梁。它让你能在 AIO Hub 中实时观察 VCP 的运行状态，又能将 AIO Hub 的工具能力共享给 VCP 网络中的 AI Agent，实现双向能力互通。</p><p>简单来说，VCP 连接器就是你的 <strong>VCP 可视化控制台</strong>——既能看，又能用。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>实时消息监控</strong>：以可视化的卡片形式实时接收 VCP 服务器的运行时广播消息，包括 RAG 检索详情、元思考链推理过程、Agent 私聊预览、AI 记忆回溯和插件执行状态，是调试 VCP 工作流的绝佳窗口</li><li><strong>分布式节点</strong>：将 AIO Hub 注册为 VCP 分布式网络中的一个节点，让你的 AI Agent 能远程调用 AIO Hub 的本地工具（如文件操作、数据处理等）</li><li><strong>工具桥接（双向共享）</strong>：动态发现 VCP 服务器上的原生插件，并将其映射为 AIO Hub 的内部工具；反过来也能将 AIO Hub 的工具暴露给 VCP 网络。一套连接，双重共享</li><li><strong>连接配置自动探测</strong>：只需指定 VCP 安装目录，系统自动读取 <code>config.env</code> 文件，解析出 WebSocket 地址和鉴权 Key，无需手动记忆配置</li><li><strong>分离窗口支持</strong>：消息监控面板可以拖拽为独立窗口，让你在工作的同时实时观察 VCP 运行状态</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h3><p>在开始之前，你需要有一个正在运行的 <a href="https://github.com/lioensky/VCPToolBox" target="_blank" rel="noreferrer">VCP 服务器</a>。VCP 连接器是一个客户端工具，它通过 WebSocket 与 VCP 服务器建立连接。</p><h3 id="首次连接-4-步走" tabindex="-1">首次连接 4 步走 <a class="header-anchor" href="#首次连接-4-步走" aria-label="Permalink to &quot;首次连接 4 步走&quot;">​</a></h3><p><strong>第一步：打开 VCP 连接器</strong></p><p>在左侧工具列表中找到 <strong>VCP 连接器</strong>，点击进入。你会看到左右分栏的布局：左侧是配置面板，右侧是消息监控和分布式节点两个标签页。</p><blockquote><p>TODO: 截图 - VCP 连接器整体界面，标注左侧配置栏和右侧 Tab 标签</p></blockquote><p><strong>第二步：配置连接</strong></p><p>在左侧的&quot;VCP 连接与过滤&quot;面板中，你可以选择以下两种方式之一来配置连接：</p><ul><li><strong>方式一（推荐）：选择 VCP 安装目录</strong> —— 点击最上方的文件夹图标按钮，从文件系统选择你的 VCP 安装目录。系统会自动读取该目录下的 <code>config.env</code> 文件，自动填入 WebSocket 地址和 VCP Key。</li><li><strong>方式二：手动填写</strong> —— 如果 VCP 服务器不在本地或无法自动探测，可以手动输入 WebSocket 地址和 VCP Key。</li></ul><p>填写完成后，开启 <strong>自动连接</strong> 开关（可选，开启后应用启动时自动连接），然后点击 <strong>连接</strong> 按钮。</p><blockquote><p>TODO: 截图 - 左侧配置面板，标注 VCP 目录选择按钮、地址/Key 输入框、连接按钮</p></blockquote><p><strong>第三步：确认连接状态</strong></p><p>连接成功后，左侧面板会显示连接状态（绿色标识），同时右侧消息监控区域会开始接收来自 VCP 服务器的广播消息。</p><blockquote><p>TODO: 截图 - 连接成功后的状态展示，标注网络延迟和重连次数</p></blockquote><p><strong>第四步：开始使用</strong></p><p>连接建立后，你就可以：</p><ul><li>切换到 <strong>消息监控</strong> Tab 查看 VCP 的实时运行日志</li><li>切换到 <strong>分布式节点</strong> Tab 管理暴露给 VCP 的工具</li><li>如果需要，开启 <strong>工具桥接</strong> 来使用 VCP 服务器上的插件</li></ul><blockquote><p>TODO: 截图 - 消息监控 Tab 中展示实时接收到的各类消息卡片</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="连接配置面板" tabindex="-1">连接配置面板 <a class="header-anchor" href="#连接配置面板" aria-label="Permalink to &quot;连接配置面板&quot;">​</a></h3><p>左侧的配置面板包含两个核心功能区：连接管理和消息过滤。</p><h4 id="连接管理" tabindex="-1">连接管理 <a class="header-anchor" href="#连接管理" aria-label="Permalink to &quot;连接管理&quot;">​</a></h4><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>VCP 目录</td><td>选择 VCP 安装目录，自动探测连接参数</td></tr><tr><td>WebSocket 地址</td><td>VCP 服务器的 WS 地址，如 <code>ws://192.168.1.100:8322</code></td></tr><tr><td>VCP Key</td><td>VCP 的鉴权密钥，从 <code>config.env</code> 中的 <code>VCP_Key</code> 获取</td></tr><tr><td>连接模式</td><td>支持三种模式：仅监控、仅分布式节点、全功能（两者兼有）</td></tr><tr><td>自动连接</td><td>开启后应用启动时自动尝试连接 VCP</td></tr><tr><td>连接/断开</td><td>手动控制连接的建立与关闭</td></tr></tbody></table><blockquote><p>TODO: 截图 - 连接面板完整视图，标注所有配置项</p></blockquote><h4 id="连接模式详解" tabindex="-1">连接模式详解 <a class="header-anchor" href="#连接模式详解" aria-label="Permalink to &quot;连接模式详解&quot;">​</a></h4><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td><code>observer</code></td><td>仅监听广播消息，不参与分布式调用</td><td>只想看 VCP 的运行日志和调试信息</td></tr><tr><td><code>distributed</code></td><td>仅注册为分布式节点，不接收广播消息</td><td>只想让 VCP Agent 调用你的本地工具</td></tr><tr><td><code>both</code>（默认）</td><td>同时建立两条连接，兼具监控与分布式能力</td><td>既想看日志，又想共享工具</td></tr></tbody></table><p>连接模式可以在配置面板的&quot;监控设置&quot;中进行选择。</p><blockquote><p>TODO: 截图 - 连接模式选择下拉框</p></blockquote><h4 id="消息过滤" tabindex="-1">消息过滤 <a class="header-anchor" href="#消息过滤" aria-label="Permalink to &quot;消息过滤&quot;">​</a></h4><p>在连接配置下方，是消息过滤面板。VCP 广播的消息分为六种类型，每种都有独立的颜色标识：</p><table tabindex="0"><thead><tr><th>类型</th><th>标签</th><th>颜色</th><th>说明</th></tr></thead><tbody><tr><td>RAG 检索详情</td><td>RAG</td><td>蓝色</td><td>向量检索的查询、评分、标签匹配详情</td></tr><tr><td>元思考链</td><td>Chain</td><td>紫色</td><td>多阶段推理过程的完整链路</td></tr><tr><td>Agent 私聊</td><td>Agent</td><td>黄色</td><td>Agent 间私聊的查询与响应预览</td></tr><tr><td>记忆回溯</td><td>Memo</td><td>绿色</td><td>AI 记忆/日记的检索结果</td></tr><tr><td>插件状态</td><td>Plugin</td><td>灰色</td><td>插件执行步骤的状态变更</td></tr><tr><td>运行日志</td><td>Log</td><td>灰色</td><td>VCP 运行时日志（工具执行、任务通知、错误报告）</td></tr></tbody></table><p>你可以通过顶部的类型按钮选择性查看特定类型的消息，也可以通过关键词搜索框快速定位关心的内容。<strong>暂停</strong> 按钮可以临时冻结消息接收，方便你仔细阅读当前内容。</p><blockquote><p>TODO: 截图 - 消息过滤面板，标注类型切换按钮和搜索框</p></blockquote><h3 id="消息监控" tabindex="-1">消息监控 <a class="header-anchor" href="#消息监控" aria-label="Permalink to &quot;消息监控&quot;">​</a></h3><p>消息监控标签页是 VCP 运行状态的&quot;可视化仪表盘&quot;，以卡片流的形式实时展示 VCP 广播的所有运行时事件。</p><h4 id="消息流" tabindex="-1">消息流 <a class="header-anchor" href="#消息流" aria-label="Permalink to &quot;消息流&quot;">​</a></h4><p>消息按倒序排列（最新消息在顶部），支持虚拟滚动，即使有数千条消息也能保持流畅。每条消息都以卡片形式呈现，包含：</p><ul><li><strong>类型图标与颜色</strong>：根据消息类型自动匹配对应的图标和颜色标识</li><li><strong>时间戳</strong>：消息的精确时间</li><li><strong>内容详情</strong>：不同类型展示不同的核心信息</li></ul><blockquote><p>TODO: 截图 - 消息监控页面的消息卡片流</p></blockquote><h4 id="消息卡片详解" tabindex="-1">消息卡片详解 <a class="header-anchor" href="#消息卡片详解" aria-label="Permalink to &quot;消息卡片详解&quot;">​</a></h4><p>每种消息类型的卡片展示不同的核心信息：</p><p><strong>RAG 检索详情卡</strong>：</p><ul><li>显示数据库名、查询文本、K 值、耗时</li><li>展示检索结果的评分列表，评分高低通过颜色深浅标识</li><li>核心标签匹配情况高亮显示</li><li>支持展开/折叠查看完整详情</li></ul><blockquote><p>TODO: 截图 - RAG 检索详情卡片</p></blockquote><p><strong>元思考链卡</strong>：</p><ul><li>显示链名和查询文本</li><li>阶段路径以胶囊节点 + 箭头形式可视化展示</li><li>点击可展开查看每个阶段的详细推理结果</li></ul><blockquote><p>TODO: 截图 - 元思考链卡片，展示阶段路径可视化</p></blockquote><p><strong>Agent 私聊预览卡</strong>：</p><ul><li>显示 Agent 名称</li><li>使用气泡对的形式展示 Query 和 Response</li></ul><p><strong>记忆回溯卡</strong>：</p><ul><li>显示记忆模式（如联想、语义等）</li><li>展示记录条数和提取内容预览</li></ul><p><strong>插件状态卡</strong>：</p><ul><li>显示插件名称和当前步骤</li><li>状态标签（等待/运行中/已完成/失败）一目了然</li></ul><p><strong>运行日志卡</strong>：</p><ul><li>显示工具名、来源标签</li><li>状态标签（成功/错误）清晰区分</li><li>错误日志使用红色高亮</li></ul><h4 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h4><p>监控页面顶部提供以下工具：</p><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td>连接状态标签</td><td>实时显示当前连接状态</td></tr><tr><td>消息计数</td><td>显示当前消息总量</td></tr><tr><td>消息速率</td><td>显示每分钟消息接收速率</td></tr><tr><td>搜索框</td><td>按关键词在消息内容中搜索</td></tr><tr><td>暂停/继续</td><td>临时停止/恢复消息接收</td></tr><tr><td>清空</td><td>清空当前消息列表</td></tr><tr><td>导出</td><td>将过滤后的消息导出为 JSON 文件</td></tr></tbody></table><blockquote><p>TODO: 截图 - 监控页面工具栏，标注各项按钮</p></blockquote><h4 id="分离窗口" tabindex="-1">分离窗口 <a class="header-anchor" href="#分离窗口" aria-label="Permalink to &quot;分离窗口&quot;">​</a></h4><p>点击消息监控面板的分离按钮，可以将监控页面拖拽为一个独立的窗口。这样你就可以在其他工具中工作时，把 VCP 的消息监控放在另一个显示器上持续观察。</p><p>当监控窗口被分离后，主窗口会显示一个占位提示，点击 <strong>收回面板</strong> 即可将监控窗口重新合入主窗口。</p><blockquote><p>TODO: 截图 - 分离后的监控窗口</p></blockquote><h3 id="分布式节点" tabindex="-1">分布式节点 <a class="header-anchor" href="#分布式节点" aria-label="Permalink to &quot;分布式节点&quot;">​</a></h3><p>分布式节点标签页让你能将 AIO Hub 注册为 VCP 网络中的一个&quot;能力节点&quot;，VCP 中的 AI Agent 可以通过网络远程调用你暴露的工具方法。</p><h4 id="节点状态面板" tabindex="-1">节点状态面板 <a class="header-anchor" href="#节点状态面板" aria-label="Permalink to &quot;节点状态面板&quot;">​</a></h4><p>展示节点的运行状态和配置信息：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>节点名称</td><td>自定义节点在 VCP 网络中的显示名称</td></tr><tr><td>服务器地址</td><td>已连接的 VCP 服务器地址（只读，共享自连接配置）</td></tr><tr><td>节点 ID</td><td>VCP 服务器分配的节点唯一标识</td></tr><tr><td>最近心跳</td><td>最后一次心跳上报的时间</td></tr><tr><td>自动注册工具</td><td>开启后自动扫描并注册可暴露的工具</td></tr></tbody></table><blockquote><p>TODO: 截图 - 节点状态面板，标注节点 ID 和心跳信息</p></blockquote><h4 id="暴露工具管理" tabindex="-1">暴露工具管理 <a class="header-anchor" href="#暴露工具管理" aria-label="Permalink to &quot;暴露工具管理&quot;">​</a></h4><p>在分布式节点模式下，你可以精细控制哪些工具暴露给 VCP 网络：</p><ul><li><strong>自动发现开关</strong>：开启后自动扫描所有标记为 <code>agentCallable</code> 或 <code>distributedExposed</code> 的工具方法</li><li><strong>手动添加</strong>：从所有已注册的工具中搜索并添加特定工具到暴露列表</li><li><strong>工具分类标识</strong>： <ul><li>🏷️ <strong>内置</strong>：VCP 协议强制要求的工具（如文件读取），不可禁用或移除</li><li>🔄 <strong>自动</strong>：通过自动发现扫描到的 AI 工具，可启用/禁用</li><li>✋ <strong>手动</strong>：你手动添加到暴露列表的工具，可启用/禁用/移除</li></ul></li><li><strong>同步状态</strong>：每个工具右侧显示其是否已成功同步到 VCP 服务器</li></ul><blockquote><p>TODO: 截图 - 暴露工具列表，标注内置/自动/手动的分类标识</p></blockquote><p><strong>安全提示</strong>：只有明确标记为 <code>distributedExposed: true</code> 的工具方法才能被远程调用。这意味着你可以精细控制哪些能力对外开放，避免敏感操作被未授权调用。</p><h3 id="工具桥接" tabindex="-1">工具桥接 <a class="header-anchor" href="#工具桥接" aria-label="Permalink to &quot;工具桥接&quot;">​</a></h3><p>工具桥接是 VCP 连接器的&quot;双向能力共享&quot;功能。开启后，VCP 服务器上的原生插件会被动态发现并映射为 AIO Hub 的内部工具——这样一来，AIO Hub 的本地 Agent 也能使用 VCP 的插件能力。</p><h4 id="开启桥接" tabindex="-1">开启桥接 <a class="header-anchor" href="#开启桥接" aria-label="Permalink to &quot;开启桥接&quot;">​</a></h4><ol><li>在 <strong>分布式节点</strong> Tab 中找到&quot;桥接工具&quot;区域</li><li>打开全局开关启用桥接功能</li><li>系统会自动从 VCP 服务器拉取可用插件清单</li></ol><blockquote><p>TODO: 截图 - 桥接工具列表，标注全局开关</p></blockquote><h4 id="权限控制" tabindex="-1">权限控制 <a class="header-anchor" href="#权限控制" aria-label="Permalink to &quot;权限控制&quot;">​</a></h4><p>桥接工具支持在命令级别进行精细的权限管理：</p><ul><li><strong>启用/禁用</strong>：你可以单独启用或禁用某个远程插件，防止 Agent 调用不安全的远程命令</li><li><strong>配置同步</strong>：VCP 插件的配置项会同步到 AIO Hub，支持在 AIO UI 中直接修改远程插件的参数</li></ul><blockquote><p>TODO: 截图 - 桥接工具权限控制，标注启用/禁用开关</p></blockquote><h3 id="表情包集成" tabindex="-1">表情包集成 <a class="header-anchor" href="#表情包集成" aria-label="Permalink to &quot;表情包集成&quot;">​</a></h3><p>如果 VCP 服务器配置了图片服务（<code>Image_Key</code>），VCP 连接器会自动加载 VCP 的表情包库，让 AIO Hub 的聊天功能可以使用 VCP 服务器上的表情资源。</p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="自动启动与后台连接" tabindex="-1">自动启动与后台连接 <a class="header-anchor" href="#自动启动与后台连接" aria-label="Permalink to &quot;自动启动与后台连接&quot;">​</a></h3><p>在左侧配置面板中开启 <strong>自动连接</strong> 开关后，每次启动 AIO Hub 时都会自动尝试连接 VCP 服务器。配合 <strong>自动注册工具</strong> 开关，VCP 连接器会在后台静默完成连接和工具注册——即使你没有打开 VCP 连接器的界面。</p><p>这对于设置了&quot;跟随应用自启&quot;的 VCP 服务器特别有用——两者启动后自动建立连接，无需任何手动操作。</p><h3 id="同时使用三条连接" tabindex="-1">同时使用三条连接 <a class="header-anchor" href="#同时使用三条连接" aria-label="Permalink to &quot;同时使用三条连接&quot;">​</a></h3><p>VCP 连接器实际上会管理多条 WebSocket 连接，每条都有独立的连接守卫和心跳机制：</p><ul><li><strong>Observer 连接</strong>：接收 VCP 广播的运行时消息（监控功能）</li><li><strong>Distributed 连接</strong>：处理工具注册、远程调用和心跳上报（分布式节点功能）</li><li><strong>桥接通道</strong>：通过 Distributed 连接进行插件清单拉取和远程代理调用</li></ul><p>三条连接相互独立，一条连接出现问题时不会影响其他连接的正常运作。</p><h3 id="结合分离窗口构建监控屏" tabindex="-1">结合分离窗口构建监控屏 <a class="header-anchor" href="#结合分离窗口构建监控屏" aria-label="Permalink to &quot;结合分离窗口构建监控屏&quot;">​</a></h3><p>如果你有多显示器环境，可以这样操作：</p><ol><li>打开 VCP 连接器，建立连接</li><li>点击消息监控面板的 <strong>分离</strong> 按钮，将监控窗口拖拽到副显示器</li><li>在主显示器上继续使用其他 AIO Hub 工具</li><li>副显示器上实时展示 VCP 的运行状态</li></ol><p>这是一种非常高效的&quot;一边干活、一边监控&quot;的工作模式。</p><h3 id="使用通知系统跟进-vcp-任务" tabindex="-1">使用通知系统跟进 VCP 任务 <a class="header-anchor" href="#使用通知系统跟进-vcp-任务" aria-label="Permalink to &quot;使用通知系统跟进 VCP 任务&quot;">​</a></h3><p>VCP 运行日志中的特定事件会通过 AIO Hub 的通知系统推送到你：</p><ul><li><strong>错误事件</strong>：VCP 工具执行报错时，自动推送错误通知，可点击查看详情</li><li><strong>任务启动</strong>：VCP 任务创建时，推送任务启动通知</li><li><strong>完成提示</strong>：任务归档、完成或成功时，以浮动提示形式展示</li></ul><p>你可以在 AIO Hub 的 <strong>通知中心</strong> 中查看所有 VCP 相关的历史通知。</p><blockquote><p>TODO: 截图 - VCP 任务通知在通知中心中的展示</p></blockquote><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-连接不上-vcp-服务器怎么办" tabindex="-1">Q：连接不上 VCP 服务器怎么办？ <a class="header-anchor" href="#q-连接不上-vcp-服务器怎么办" aria-label="Permalink to &quot;Q：连接不上 VCP 服务器怎么办？&quot;">​</a></h3><p>最常见的原因是 VCP 服务器没有运行。请先确认 VCP 服务器已启动并正常运行。</p><p>如果服务器确认在运行但仍无法连接，可以尝试：</p><ol><li>检查 WebSocket 地址格式是否正确（标准格式：<code>ws://IP:端口</code>）</li><li>确认 VCP Key 是否正确（可以在 VCP 安装目录下的 <code>config.env</code> 文件中找到）</li><li>检查防火墙是否阻止了连接</li><li>如果是远程服务器，确保服务器允许 WebSocket 连接</li></ol><h3 id="q-消息监控面板没有显示任何消息" tabindex="-1">Q：消息监控面板没有显示任何消息？ <a class="header-anchor" href="#q-消息监控面板没有显示任何消息" aria-label="Permalink to &quot;Q：消息监控面板没有显示任何消息？&quot;">​</a></h3><p>可能的原因：</p><ol><li><strong>未建立连接</strong>：检查连接状态是否为&quot;已连接&quot;，如果不是请点击连接按钮</li><li><strong>连接模式不对</strong>：如果选择了 <code>distributed</code> 模式，Observer 连接不会建立，自然收不到广播消息。请切换为 <code>both</code> 或 <code>observer</code> 模式</li><li><strong>暂停状态</strong>：检查消息过滤面板的&quot;暂停&quot;按钮是否被激活，再次点击即可恢复</li><li><strong>类型过滤</strong>：检查类型过滤按钮是否全部被选中（可以点击&quot;全部&quot;按钮重置）</li><li><strong>VCP 服务器没有触发事件</strong>：VCP 只在有实际运行时事件时才会广播消息，这是正常现象</li></ol><h3 id="q-暴露给-vcp-的工具太多-怎么控制" tabindex="-1">Q：暴露给 VCP 的工具太多，怎么控制？ <a class="header-anchor" href="#q-暴露给-vcp-的工具太多-怎么控制" aria-label="Permalink to &quot;Q：暴露给 VCP 的工具太多，怎么控制？&quot;">​</a></h3><p>你可以在 <strong>分布式节点 &gt; 暴露工具列表</strong> 中进行精细控制：</p><ol><li>关闭 <strong>自动注册工具</strong> 开关，这样只有你手动添加的工具才会被暴露</li><li>在工具列表中，点击工具右侧的开关来临时禁用某个工具</li><li>对于手动添加的工具，可以直接从列表中移除</li></ol><p>这样你就可以只暴露那些你确实想让 VCP Agent 调用的工具了。</p><h3 id="q-工具桥接和分布式节点有什么区别" tabindex="-1">Q：工具桥接和分布式节点有什么区别？ <a class="header-anchor" href="#q-工具桥接和分布式节点有什么区别" aria-label="Permalink to &quot;Q：工具桥接和分布式节点有什么区别？&quot;">​</a></h3><p>这是两个互补但不同的功能：</p><ul><li><strong>分布式节点</strong>：AIO Hub 作为节点加入 VCP 网络，AIO 的工具可以被 VCP 中的 Agent 调用（单向：AIO → VCP）</li><li><strong>工具桥接</strong>：VCP 服务器上的插件被映射到 AIO Hub 内部，AIO 的本地 Agent 也可以调用 VCP 的插件（反向：VCP → AIO）</li></ul><p>简单来说，分布式节点是&quot;给出去&quot;，工具桥接是&quot;拿回来&quot;——两者结合实现双向工具共享。</p><h3 id="q-断开连接后重新连接需要手动操作吗" tabindex="-1">Q：断开连接后重新连接需要手动操作吗？ <a class="header-anchor" href="#q-断开连接后重新连接需要手动操作吗" aria-label="Permalink to &quot;Q：断开连接后重新连接需要手动操作吗？&quot;">​</a></h3><p>不需要。如果你开启了 <strong>自动连接</strong> 开关：</p><ul><li>网络断开后，系统会自动尝试重连</li><li>重连策略采用指数退避（1 秒 → 2 秒 → 4 秒 → ... → 最多 30 秒），外加随机抖动，避免多个连接同时重连造成服务器压力</li><li>连接恢复后会自动继续接收消息和注册工具</li></ul><p>如果你没有开启自动连接，则需要手动点击 <strong>连接</strong> 按钮。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果你需要快速重置连接，可以直接点击 <strong>断开</strong> 后再点 <strong>连接</strong>。</p></div>',130)])])}const p=o(l,[["render",d]]);export{b as __pageData,p as default};
